-- ============================================================================
-- MASSACHUSETTS development_reports seed — REPRODUCIBLE pg_net REFRESH SCRIPT
-- (pattern: docs/michigan-development-reports-seed.sql; run in the Supabase SQL editor)
--
-- Built 2026-07-15: all 627 modeled MA ZIPs (the 592-ZIP statewide build + the
-- founder-approved SUFFOLK 35-ZIP EXPANSION — Boston/Chelsea/Revere/Winthrop pages,
-- migration suffolk_boston_zip_expansion) cached through the live engine and
-- materialized into app_*. Development depth from FOUR first-party sources wired this
-- pass: boston-approved-building-permits (the FIRST `ckan` entry, on the new ADDITIVE
-- sources/ckan.ts connector — datastore_search_sql; fresh same-day; native zip + own
-- lat/lng; founder whitelist keeps Erect/New Construction, Long Form/Alteration,
-- Amendment to a Long Form, Foundation, Use of Premises — Short Form DROPPED) plus the
-- cambridge new-construction / addition-alteration / demolition Socrata trio (spatial
-- point scoping; Active/Complete verbatim). Bidirectional coverage-gate proof ran with
-- live receipts (02128 = Boston only; 02138 = Cambridge only; 48226 = Detroit only).
-- Worcester STALLED (2025-09-09) -> nightly reprobe; Springfield/Somerville/statewide
-- rejected with receipts (docs/source-registry.md "MASSACHUSETTS WIRE PASS"). Centroids
-- pinned to zipcodes PyPI v3.0.0; 0 quarantined (05501/05544 are Andover IRS ZIPs
-- physically in MA). INDEX POLICY: substance gate stamps indexable automatically;
-- throttled sitemap (250 newcomers/day) rolls new pages in — no manual flip.
-- ============================================================================
drop table if exists public._ma_zips;
create table public._ma_zips(zip text primary key, lat float8, lng float8);

-- FIRE in waves of ~90 (offset 0/90/180/270/360/450/540; wait ~2.5 min per wave) ------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', zip, 'lat', lat, 'lng', lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 120000)) as fired
from (select * from public._ma_zips order by zip limit 90 offset 0) w;

-- COLLECT after each wave (transient-safe upsert) -----------------------------------
select (j->>'zip'), (j->'home'->>'lat')::float8, (j->'home'->>'lng')::float8, j->'counts', j->'sites',
       coalesce((j->>'paywall')::bool,false),
       'zipcodes PyPI v3.0.0 centroid; get-address-report ZIP mode; Massachusetts batch 2026-07-15',
       now()
from (
  select distinct on ((content::jsonb->>'zip')) content::jsonb j
  from net._http_response resp
  where resp.status_code = 200 and left(ltrim(resp.content),1)='{'
    and (content::jsonb->>'zip') in (select zip from public._ma_zips)
    and resp.created > now() - interval '30 minutes'
  order by (content::jsonb->>'zip'), resp.created desc
) r
on conflict (zip) do update set home_lat=excluded.home_lat, home_lng=excluded.home_lng,
  counts=excluded.counts, sites=excluded.sites, paywall=excluded.paywall,
  source_vintage=excluded.source_vintage, refreshed_at=excluded.refreshed_at
where jsonb_array_length(excluded.sites) > 0 or jsonb_array_length(public.development_reports.sites) = 0;

-- RE-FIRE stragglers (180s timeout), then re-collect --------------------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', z.zip, 'lat', z.lat, 'lng', z.lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 180000)) as refired
from public._ma_zips z
where not exists (select 1 from public.development_reports dr where dr.zip = z.zip);

-- MATERIALIZE + verify ---------------------------------------------------------------
select public.app_refresh_all();
select (select count(*) from public.development_reports dr join public._ma_zips z on z.zip=dr.zip) as ma_cached,
       (select count(*) from public.app_community_meta m join public._ma_zips z on z.zip=m.zip where m.indexable) as ma_indexable;
